}
.ov-date {
    font-family: var(--font-ui);
    font-size: 0.75rem;
    color: var(--text-faint);
}

.ov-body {
    font-family: var(--font-serif);
    font-size: 0.92rem;
    line-height: 1.7;
    color: var(--text-body);
    cursor: pointer;
}

.ov-meta-bar {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: 0.6rem;
    border-top: 1px solid var(--border-card);
}
.ov-reply-pill {
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    background-color: var(--bg-pill);
    border-radius: 10px;
    padding: 0.2rem 0.6rem;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--accent-sage);
    cursor: pointer;
}
.ov-full-date {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    color: var(--text-faint);
}

.ov-reply-row {
    display: flex;
    align-items: flex-end;
    gap: 0.5rem;
    padding-top: 0.25rem;
}
.ov-reply-avatar {
    width: 24px;
    height: 24px;
    border-radius: 50%;
    object-fit: cover;
}
.ov-reply-input {
    flex: 1;
    min-height: 1.4rem;
    outline: none;
    border: none;
    border-bottom: 1px solid var(--border-card);
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-style: italic;
    color: var(--text-primary);
    padding-bottom: 0.25rem;
    transition: border-color 0.2s ease;
}
.ov-reply-input:empty::before {
    content: attr(data-placeholder);
    color: var(--text-faint);
    cursor: text;
}
.ov-reply-input:focus {
    border-bottom: 2px solid var(--accent-sage);
}

.ov-btn-row {
    display: flex;
    gap: 0.6rem;
    justify-content: flex-end;
    overflow: hidden;
}
.ov-btn-cancel {
    cursor: pointer;
    background-color: transparent;
    border: 1px solid var(--border-card);
    color: var(--text-primary);
    border-radius: 20px;
    padding: 0.35rem 1rem;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 500;
    transition: background-color 0.15s ease;
}
.ov-btn-cancel:hover {
    background-color: var(--bg-hover);
}
.ov-btn-submit {
    cursor: pointer;
    border: none;
    padding: 0.35rem 1rem;
    border-radius: 20px;
    background-color: var(--accent-sage);
    color: #ffffff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    transition: opacity 0.15s ease;
}
.ov-btn-submit:hover {
    opacity: 0.88;
}
.ov-btn-submit.ov-btn-disabled {
    cursor: default;
    user-select: none;
    opacity: 0.45;
}

/* ── Reply Card (rc-) ── */
.rc-thread {
    padding-left: calc(var(--depth, 0) * 1.25rem);
    width: 100%;
    box-sizing: border-box;
}

.rc-card {
    position: relative;
    display: flex;
    align-items: stretch;
    padding: 0.75rem 0;
    border-bottom: 1px solid var(--border-card);
}
.rc-card:last-child {
    border-bottom: none;
}

.rc-thread-line {
    position: absolute;
    left: -0.65rem;
    top: 0;
    bottom: 0;
    width: 2px;
    background-color: var(--border-card);
    border-radius: 1px;
    transition: background-color 0.2s ease;
}
.rc-card:hover > .rc-thread-line {
    background-color: var(--accent-sage);
}

.rc-content {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    flex: 1;
    min-width: 0;
}

.rc-user-row {
    display: flex;
    align-items: center;
    gap: 0.35rem;
}
.rc-avatar {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
}
.rc-username {
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--text-heading);
}
.rc-dot {
    color: var(--text-separator);
    font-size: 0.75rem;
    line-height: 1;
}
.rc-date {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    color: var(--text-faint);
}

.rc-body {
    font-family: var(--font-serif);
    font-size: 0.85rem;
    line-height: 1.65;
    color: var(--text-body);
}

.rc-action-row {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding-top: 0.15rem;
}
.rc-toggle-btn {
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    cursor: pointer;
    background: none;
    border: none;
    padding: 0.2rem 0.4rem;
    border-radius: 6px;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--text-muted);
    transition: color 0.15s ease, background-color 0.15s ease;
}
.rc-toggle-btn:hover {
    color: var(--accent-sage);
    background-color: var(--bg-pill);
}

.rc-reply-input-wrapper {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    overflow: hidden;
    padding-top: 0.25rem;
}

.rc-load-more {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    background: none;
    border: 1px solid var(--border-card);
    border-radius: 20px;
    padding: 0.35rem 1rem;
    margin-top: 0.5rem;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--accent-sage);
    transition: background-color 0.15s ease;
}
.rc-load-more:hover {
    background-color: var(--bg-pill);
}
@media(max-width: 480px){
    .visited-profile-opinion-content{
        font-weight: 400;
        font-size: 0.8rem;
    }
    .visited-profile-opinions-container{
        margin-bottom: 4rem;
        height: fit-content;
    }
    .opinions-page-parent-container {
        display: flex;
        flex-direction: column;
        justify-content: flex-start;
        align-items: center;
        width: 100%;
        top: 60px;
        height: 100dvh;
        gap: 0.5rem;
        padding: 1rem 0 0rem 0;
    }

    .oe-card {
        width: min(420px, 92%);
        border-radius: 10px;
    }
    .oe-header {
        padding: 0.7rem 0.85rem;
    }
    .oe-title {
        font-size: 0.82rem;
    }
    .oe-body {
        padding: 0.6rem 0.85rem;
    }
    .oe-textarea {
        min-height: 100px;
        font-size: 0.85rem;
    }
    .oe-footer {
        padding: 0.5rem 0.85rem 0.7rem 0.85rem;
    }
    .oe-save-btn {
        font-size: 0.72rem;
        padding: 0.3rem 0.9rem;
    }

    .opinions-page-parent-container .so-card-wrapper {
        width: 94%;
    }

    /* ── Sidebar Opinion Card mobile ── */
    .so-card-wrapper {
        width: 100%;
        padding: 0;
        margin-bottom: 0.35rem;
    }
    .so-avatar-outer {
        width: 30px;
        height: 30px;
    }
    .so-avatar-outer .so-avatar {
        width: 30px;
        height: 30px;
    }
    .so-avatar-outer.avatar-ring-legend,
    .so-avatar-outer.avatar-ring-og {
        display: flex;
        align-items: center;
        justify-content: center;
        width: auto;
        height: auto;
    }
    .so-avatar-outer.avatar-ring-legend .so-avatar,
    .so-avatar-outer.avatar-ring-og .so-avatar {
        width: 30px;
        height: 30px;
    }
    .so-card {
        padding: 0.75rem 0.8rem;
        border-radius: 10px;
        gap: 0.4rem;
        overflow: hidden;
        margin-bottom: 2rem;
    }
    .so-avatar {
        width: 30px;
        height: 30px;
    }
    .so-username {
        font-size: 0.94rem;
        max-width: 120px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
    }
    .so-handle{
        max-width: 110px;
    }
    .so-body {
        font-size: 1rem;
        line-height: 1.35;
        margin-left: 2.35rem;
    }
    .so-meta-bar {
        margin-left: 2.35rem;
    }
    .so-reply-pill {
        font-size: 0.8rem;
    }

    /* ── Opinion Viewer mobile ── */
    .ov-card {
        border-radius: 10px;
        padding: 0.85rem;
        gap: 0.55rem;
    }
    .ov-avatar {
        width: 28px;
        height: 28px;
    }
    .ov-username {
        font-size: 0.78rem;
        max-width: 120px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
    }
    .ov-body {
        font-size: 0.85rem;
        line-height: 1.6;
    }
    .ov-reply-avatar {
        width: 20px;
        height: 20px;
    }
    .ov-reply-input {
        font-size: 0.78rem;
    }
    .ov-btn-cancel,
    .ov-btn-submit {
        font-size: 0.72rem;
        padding: 0.3rem 0.8rem;
    }

    /* ── Reply Card mobile ── */
    .rc-thread {
        padding-left: calc(var(--depth, 0) * 0.75rem);
    }
    .rc-avatar {
        width: 18px;
        height: 18px;
    }
    .rc-username {
        font-size: 0.72rem;
        max-width: 100px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
    }
    .rc-body {
        font-size: 0.8rem;
    }
    .rc-toggle-btn {
        font-size: 0.68rem;
    }
    .rc-load-more {
        font-size: 0.7rem;
    }

    /* ── Write Opinion FAB mobile ── */
    .write-opinion-fab {
        right: 1.25rem;
        bottom: 6.5rem;
        width: 54px;
        height: 54px;
    }
}
@media(max-width: 432px){
    .oe-card {
        width: 92%;
    }

    .write-opinion-fab {
        right: 1rem;
        bottom: 6rem;
        width: 50px;
        height: 50px;
    }
    .opinion-fab-icon-wrapper {
        width: 22px;
        height: 22px;
    }
    .opinion-fab-icon-wrapper svg {
        width: 22px;
        height: 22px;
    }
}
